// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

library EnsLabelUtils {
    error InvalidENSLabel();

    bytes1 private constant DASH = 0x2d;
    bytes1 private constant DOT = 0x2e;
    bytes1 private constant ZERO = 0x30;
    bytes1 private constant NINE = 0x39;
    bytes1 private constant LOWER_A = 0x61;
    bytes1 private constant LOWER_Z = 0x7a;

    /// @dev Strict ASCII label policy for predictable ENS auth routing:
    /// 1..63 chars, [a-z0-9-], no dots, no leading/trailing dash.
    function requireValidLabel(string memory label) internal pure {
        bytes memory b = bytes(label);
        uint256 len = b.length;
        if (len == 0 || len > 63) revert InvalidENSLabel();
        if (b[0] == DASH || b[len - 1] == DASH) revert InvalidENSLabel();

        for (uint256 i = 0; i < len;) {
            bytes1 c = b[i];
            if (c == DOT) revert InvalidENSLabel();

            bool isDigit = c >= ZERO && c <= NINE;
            bool isLower = c >= LOWER_A && c <= LOWER_Z;
            if (!(isDigit || isLower || c == DASH)) revert InvalidENSLabel();

            unchecked {
                ++i;
            }
        }
    }
}

contracts/utils/ENSOwnership.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";
import "./EnsLabelUtils.sol";

library ENSOwnership {
    // Legacy note: keep this library limited to deterministic ownership checks used by
    // AGIJobManager routing (`verifyENSOwnership` + `verifyMerkleOwnership`).
    // Keep a fixed staticcall cap: enough for normal ENS stack reads while bounding griefing surface.
    uint256 private constant ENS_STATICCALL_GAS_LIMIT = 80_000;
    bytes4 private constant OWNER_OF_SELECTOR = 0x6352211e;
    bytes4 private constant GET_APPROVED_SELECTOR = 0x081812fc;
    bytes4 private constant IS_APPROVED_FOR_ALL_SELECTOR = 0xe985e9c5;
    bytes4 private constant RESOLVER_SELECTOR = 0x0178b8bf;
    bytes4 private constant ADDR_SELECTOR = 0x3b3b57de;

    function _verifyByRoot(
        address ensAddress,
        address nameWrapperAddress,
        address claimant,
        string memory subdomain,
        bytes32 rootNode
    ) private view returns (bool) {
        if (rootNode == bytes32(0)) return false;
        bytes32 subnode = keccak256(abi.encodePacked(rootNode, keccak256(bytes(subdomain))));
        if (_verifyNameWrapperOwnership(nameWrapperAddress, claimant, subnode)) {
            return true;
        }
        return _verifyResolverOwnership(ensAddress, claimant, subnode);
    }
    function verifyENSOwnership(
        address ensAddress,
        address nameWrapperAddress,
        address claimant,
        string memory subdomain,
        bytes32 rootNode
    ) external view returns (bool) {
        EnsLabelUtils.requireValidLabel(subdomain);
        if (rootNode == bytes32(0)) return false;
        bytes32 subnode = keccak256(abi.encodePacked(rootNode, keccak256(bytes(subdomain))));
        if (_verifyNameWrapperOwnership(nameWrapperAddress, claimant, subnode)) {
            return true;
        }
        return _verifyResolverOwnership(ensAddress, claimant, subnode);
    }

    function verifyENSOwnership(
        address ensAddress,
        address nameWrapperAddress,
        address claimant,
        string memory subdomain,
        bytes32 rootNode,
        bytes32 alphaRootNode
    ) external view returns (bool) {
        EnsLabelUtils.requireValidLabel(subdomain);
        return _verifyByRoot(ensAddress, nameWrapperAddress, claimant, subdomain, rootNode)
            || _verifyByRoot(ensAddress, nameWrapperAddress, claimant, subdomain, alphaRootNode);
    }

    function verifyMerkleOwnership(address claimant, bytes32[] calldata proof, bytes32 merkleRoot)
        external
        pure
        returns (bool)
    {
        return MerkleProof.verifyCalldata(proof, merkleRoot, keccak256(abi.encodePacked(claimant)));
    }

    function _verifyNameWrapperOwnership(
        address nameWrapperAddress,
        address claimant,
        bytes32 subnode
    ) private view returns (bool) {
        if (nameWrapperAddress == address(0)) return false;
        (bool ok, address owner) = _staticcallAddress(
            nameWrapperAddress,
            abi.encodeWithSelector(OWNER_OF_SELECTOR, uint256(subnode))
        );
        if (!ok || owner == address(0)) return false;
        if (owner == claimant) return true;

        address approved;
        (ok, approved) = _staticcallAddress(
            nameWrapperAddress,
            abi.encodeWithSelector(GET_APPROVED_SELECTOR, uint256(subnode))
        );
        if (ok && approved == claimant) return true;

        bool approvedForAll;
        (ok, approvedForAll) = _staticcallBool(
            nameWrapperAddress,
            abi.encodeWithSelector(IS_APPROVED_FOR_ALL_SELECTOR, owner, claimant)
        );
        return ok && approvedForAll;
    }

    function _verifyResolverOwnership(
        address ensAddress,
        address claimant,
        bytes32 subnode
    ) private view returns (bool) {
        if (ensAddress == address(0)) return false;
        (bool ok, address resolverAddress) = _staticcallAddress(
            ensAddress,
            abi.encodeWithSelector(RESOLVER_SELECTOR, subnode)
        );
        if (!ok || resolverAddress == address(0)) return false;
        address resolvedAddress;
        (ok, resolvedAddress) = _staticcallAddress(
            resolverAddress,
            abi.encodeWithSelector(ADDR_SELECTOR, subnode)
        );
        return ok && resolvedAddress == claimant;
    }

    function _staticcallAddress(address target, bytes memory payload) private view returns (bool ok, address result) {
        uint256 decoded;
        (ok, decoded) = _staticcallWord(target, payload);
        if (!ok) return (false, address(0));
        result = address(uint160(decoded));
    }

    function _staticcallBool(address target, bytes memory payload) private view returns (bool ok, bool result) {
        uint256 decoded;
        (ok, decoded) = _staticcallWord(target, payload);
        if (!ok) return (false, false);
        if (decoded > 1) return (false, false);
        result = decoded == 1;
    }

    function _staticcallWord(address target, bytes memory payload) private view returns (bool ok, uint256 word) {
        assembly {
            ok := staticcall(ENS_STATICCALL_GAS_LIMIT, target, add(payload, 0x20), mload(payload), 0x00, 0x20)
            if lt(returndatasize(), 0x20) {
                ok := 0
            }
            if ok {
                returndatacopy(0x00, 0x00, 0x20)
                word := mload(0x00)
            }
        }
    }
}

contracts/utils/ReputationMath.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/utils/math/Math.sol";

library ReputationMath {
    function computeReputationPoints(
        uint256 payout,
        uint256 duration,
        uint256 completionRequestedAt,
        uint256 assignedAt,
        bool repEligible
    ) external pure returns (uint256 reputationPoints) {
        if (!repEligible) {
            return 0;
        }
        uint256 completionTime = completionRequestedAt > assignedAt
            ? completionRequestedAt - assignedAt
            : 0;
        unchecked {
            uint256 payoutUnits = payout / 1e15;
            uint256 timeBonus;
            if (duration > completionTime) {
                timeBonus = (duration - completionTime) / 10000;
            }
            uint256 base = Math.log2(1 + payoutUnits);
            if (timeBonus > base) {
                timeBonus = base;
            }
            reputationPoints = base + timeBonus;
        }
    }
}

contracts/utils/TransferUtils.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

library TransferUtils {
    error TransferFailed();

    /// @dev Strict ERC20 call wrapper: only contract targets are accepted and return data must be
    /// either empty (non-standard tokens) or ABI-encoded bool(true).
    function safeTransfer(address token, address to, uint256 amount) external {
        if (amount == 0) return;
        if (token.code.length == 0) revert TransferFailed();
        _callOptionalReturn(token, abi.encodeWithSelector(IERC20.transfer.selector, to, amount));
    }

    /// @dev Enforces exact transfer semantics by measuring recipient balance deltas.
    /// Fee-on-transfer / deflationary transfers intentionally revert.
    function safeTransferFromExact(address token, address from, address to, uint256 amount) external {
        if (amount == 0) return;
        if (token.code.length == 0) revert TransferFailed();
        uint256 balanceBefore = _safeBalanceOf(token, to);
        _callOptionalReturn(token, abi.encodeWithSelector(IERC20.transferFrom.selector, from, to, amount));
        uint256 balanceAfter = _safeBalanceOf(token, to);
        if (balanceAfter < balanceBefore || balanceAfter - balanceBefore != amount) revert TransferFailed();
    }

    function _safeBalanceOf(address token, address account) private view returns (uint256 balance) {
        (bool success, bytes memory returndata) = token.staticcall(
            abi.encodeWithSelector(IERC20.balanceOf.selector, account)
        );
        if (!success || returndata.length != 32) revert TransferFailed();
        balance = abi.decode(returndata, (uint256));
    }

    function _callOptionalReturn(address token, bytes memory data) private {
        (bool success, bytes memory returndata) = token.call(data);
        if (!success) revert TransferFailed();
        if (returndata.length == 0) return;
        if (returndata.length == 32) {
            uint256 word;
            assembly {
                word := mload(add(returndata, 0x20))
            }
            if (word > 1 || word == 0) revert TransferFailed();
            return;
        }
        revert TransferFailed();
    }
}

contracts/utils/UriUtils.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

library UriUtils {
    error InvalidParameters();

    bytes1 private constant COLON = 0x3a;
    bytes1 private constant SLASH = 0x2f;

    function requireValidUri(string memory uri) external pure {
        bytes memory data = bytes(uri);
        if (data.length == 0) revert InvalidParameters();
        for (uint256 i = 0; i < data.length; ) {
            bytes1 c = data[i];
            if (c == 0x20 || c == 0x09 || c == 0x0a || c == 0x0d) revert InvalidParameters();
            unchecked {
                ++i;
            }
        }
    }

    function applyBaseIpfs(string memory uri, string memory baseIpfsUrl) external pure returns (string memory) {
        bytes memory uriBytes = bytes(uri);
        bytes memory baseBytes = bytes(baseIpfsUrl);
        if (_hasScheme(uriBytes) || baseBytes.length == 0) {
            return uri;
        }
        if (_startsWith(uriBytes, baseBytes)) {
            if (uriBytes.length == baseBytes.length) return uri;
            if (uriBytes[baseBytes.length] == SLASH) return uri;
        }

        bool baseEndsWithSlash = baseBytes[baseBytes.length - 1] == SLASH;
        bool uriStartsWithSlash = uriBytes.length > 0 && uriBytes[0] == SLASH;
        if (baseEndsWithSlash && uriStartsWithSlash) {
            return string(abi.encodePacked(baseIpfsUrl, _sliceFrom(uriBytes, 1)));
        }
        if (!baseEndsWithSlash && !uriStartsWithSlash) {
            return string(abi.encodePacked(baseIpfsUrl, "/", uri));
        }
        return string(abi.encodePacked(baseIpfsUrl, uri));
    }

    function _hasScheme(bytes memory uriBytes) private pure returns (bool) {
        for (uint256 i = 0; i + 2 < uriBytes.length; ) {
            if (uriBytes[i] == COLON && uriBytes[i + 1] == SLASH && uriBytes[i + 2] == SLASH) {
                return true;
            }
            unchecked {
                ++i;
            }
        }
        return false;
    }

    function _startsWith(bytes memory data, bytes memory prefix) private pure returns (bool) {
        if (data.length < prefix.length) return false;
        for (uint256 i = 0; i < prefix.length; ) {
            if (data[i] != prefix[i]) return false;
            unchecked {
                ++i;
            }
        }
        return true;
    }

    function _sliceFrom(bytes memory data, uint256 start) private pure returns (bytes memory out) {
        if (start >= data.length) return "";
        uint256 len = data.length - start;
        out = new bytes(len);
        for (uint256 i = 0; i < len; ) {
            out[i] = data[start + i];
            unchecked {
                ++i;
            }
        }
    }
}
